VALUES
  ('social-worker-moex-06510', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者評估案主需求與資源間的持續與有效關係，其資源應具有下列那些特質？①存在可用性', '["可信賴性", "貢獻性", "平衡性  ⑤妥適性", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06511', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者撰寫個案紀錄時，必須注意保密事項，下列敘述何者為正確？①做個案紀錄時，不記錄超過', '["在個案的檔案資料中，必須放入會談的逐字紀錄稿或紀錄手稿", "除非特殊狀況， 而且經主管授權，否則不將個案紀錄攜出機構", "記錄與案主隱私有關的內容時，儘量以一般字眼形容 親密關係之問題", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06512', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者在提供案主轉介服務時，連結案主與資源系統，必須追蹤和監督案主是否取得資源，及其取 得資源之過程。然而有關社會工作者提供轉介服務之原則，下列敘述何者錯誤？', '["社會工作者在提供轉介服務時，須對案主說明接受轉介機構的功能和方法，而且要具體指明其可能採 取的行動", "當案主決定接受轉介時，社會工作者須與案主一同討論希望得到的服務內容", "社會工作者提供案主可供選擇的轉介機構名單和內容後，須以尊重案主的自我決定權利為前提，提供 案主適當的建議", "社會工作者須瞭解案主面對被轉介時的感受，以確認案主是否準備好接受轉介"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06513', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「任務中心」個案工作的描述，下列何者正確：①助人者在助人過程中運用一種簡單（brief）有結構', '["主要的改變媒介 為案主本人", "主要的改變媒介為環境系統", "適用範圍是人際衝突、社會關係的不適應、角色執行困 難、資源不足等", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06514', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '當社工員處理個案面對倫理兩難情境時，依據Lowenberg和Dolgoff提及的倫理抉擇優先順序，那一項原 則屬於排序最低者？', '["自主自由", "隱私守密", "差別平等", "最小傷害"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06515', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者促進團體創造力的方法，下列敘述何者錯誤？', '["需要提出各種不同的想法，或彈性組成新的解決方法", "必須有適當水準動機，喚起成員尋找解決問題", "應要求團體成員以結構式互動程序，找出新路徑", "團體必須有合作性解決問題的氣氛"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06516', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '某學校社工師欲檢定「冒險體驗團體」和「任務中心取向團體」等二種模式對高關懷學生的復原力提升 是否有差異，上述針對相同的目標採取不同團體處遇方法的研究設計是屬於下列那一種評估設計方法？', '["AB設計", "ABAB設計", "變化指標設計", "多程序設計"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06517', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '治療團體協助成員改變他們的行為，因應及改善個人問題或心理社會創傷的復健。下列何者屬於治療團', '["社區心理衛生中心為門診病人所組的心理治療團體", "志願健康協會為想要戒菸的人組成 團體", "為單親團體舉辦遠足、跳舞和其他社會活動", "醫院為有藥癮的人組成團體"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06518', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體發展過程中團體契約的型態，下列敘述何者錯誤？', '["互賴契約是個別目標的表達，為個人取向的契約而實施", "個別契約是為了成員本身個別化的目標", "獨立契約有異於個別契約，是成員從團體經驗中重新開始", "互惠契約是工作者與成員間同意持續性會談"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06519', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在團體規劃過程中，社工員須決定團體是採取開放式或封閉式。下列敘述何者錯誤？', '["封閉式比開放式團體好，例如戒酒匿名團體的成員無須擔心身分曝光", "一個討論社區精神病患復健問題的委員會必須隨時邀請社區中途之家代表才能得到廣泛意見，因此團 體採取開放性", "團體開始與結束同一批人，不致因為有新成員的加入而妨礙原有進度", "當醫院中的病人不斷流動，社工員如果一意要成員開始到結束都是同一批人，要求一定的聚會次數， 有時是不切實際"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
